[FormControlEventHandler(formControlStr(InventTransPick, TmpInventTransWMS_InventQty), FormControlEventType::Modified)]
public static void TmpInventTransWMS_InventQty_OnModified(FormControl sender, FormControlEventArgs e)
{
    FormRun         formrun        = sender.formRun().args().caller();
    FormDataSource  inventTrans_ds =  sender.formRun().dataSource(formDataSourceStr(InventTransPick,InventTrans));
    InventTrans     inventTrans    = inventTrans_ds.cursor();


    if(formrun.name() == formStr(SalesEditLines) && inventTrans.StatusIssue == StatusIssue::OnOrder)
    {
        SalesParmLine  salesParmLine  = formrun.dataSource(formDataSourceStr(SalesEditLines,SalesParmLine)).cursor();
        SalesLine      salesLine      = salesParmLine.salesLine();
        InventQty      pickQty        = str2Num(sender.valueStr());
        InventQty      overDeliveryQty;

        if(salesLine.RemainInventPhysical < pickQty )
        {
            overDeliveryQty = salesLine.RemainInventPhysical * salesLine.overDeliveryPct / 100 + salesLine.RemainInventPhysical;

            if(overDeliveryQty >= pickQty && salesLine.overDeliveryPct)
            {
                inventTrans.Qty = -pickQty;
                inventTrans.doUpdate();
                inventTrans.reread();                   
            }

            else
            {
                throw Error(strFmt('Only over delivery %1 percent can be allowed',salesLine.overDeliveryPct));
            }
        }

        else 
        {
            inventTrans.Qty = -salesLine.RemainInventPhysical;
            inventTrans.doUpdate();
            inventTrans.reread();
        }
    }

    else if (formrun.name() == formStr(InventTransferParmShip))
    {
        InventTransferParmLine inventTransferParmLine  = formrun.dataSource(formDataSourceStr(InventTransferParmShip,InventTransferParmLine)).cursor();
        InventTransferLine     inventTransferLine      = inventTransferParmLine.inventTransferLine();
        InventQty              pickQty        = str2Num(sender.valueStr());
        InventQty              overDeliveryQty;
        InventTransOrigin      inventTransOrigin;
        InventTrans            inventTransReceipt;

        if(inventTransferLine.QtyRemainShip <= pickQty )
        {
            overDeliveryQty = inventTransferLine.QtyTransfer * inventTransferLine.OverDeliveryPct / 100 + inventTransferLine.QtyRemainShip;

            if(overDeliveryQty >= pickQty && inventTransferLine.OverDeliveryPct)
            {
                inventTrans.Qty = -pickQty;
                inventTrans.doUpdate();
                inventTrans.reread();

                select firstonly RecId from inventTransOrigin
                    where inventTransOrigin.ReferenceId == inventTransferLine.TransferId
                        && inventTransOrigin.ReferenceCategory == InventTransType::TransferOrderReceive
                join forupdate Qty from inventTransReceipt
                    where inventTransReceipt.InventTransOrigin == inventTransOrigin.RecId
                        && inventTransReceipt.StatusIssue == StatusIssue::None
                        && inventTransReceipt.StatusReceipt == StatusReceipt::Ordered
                        && inventTransReceipt.TransChildType == InventTransChildType::None;

                if(inventTransReceipt)
                {
                    ttsbegin;
                    inventTransReceipt.Qty = pickQty;
                    inventTransReceipt.doUpdate();
                   // inventTransReceipt.reread();
                    ttscommit;
                }
                ttsbegin;
                inventTransferLine.selectForUpdate(true);
                inventTransferLine.QtyRemainShip    = pickQty;
                inventTransferLine.QtyRemainReceive = pickQty;
                inventTransferLine.doUpdate();
                inventTransferLine.reread();
                ttscommit;
            }

            else
            {
                throw Error(strFmt('Only over delivery %1 percent can be allowed',inventTransferLine.OverDeliveryPct));
            }
        }
    }

  /*  else if (formrun.name() == formStr(InventTransferParmReceive))
    {
        InventTransferParmLine inventTransferParmLine  = formrun.dataSource(formDataSourceStr(InventTransferParmReceive,InventTransferParmLine)).cursor();
        InventTransferLine     inventTransferLine      = inventTransferParmLine.inventTransferLine();
        InventQty              pickQty        = str2Num(sender.valueStr());
        InventQty              overDeliveryQty;

        if(inventTransferLine.QtyRemainReceive < pickQty )
        {
            overDeliveryQty = inventTransferLine.QtyTransfer * inventTransferLine.OverDeliveryPct / 100 + inventTransferLine.QtyRemainReceive;

            if(overDeliveryQty >= pickQty && inventTransferLine.OverDeliveryPct)
            {
                inventTrans.Qty = -pickQty;
                inventTrans.doUpdate();
                inventTrans.reread();
            }

            else
            {
                throw Error(strFmt('Over delivery %1 percent can be allowed',inventTransferLine.OverDeliveryPct));
            }
        }
    }*/

}
